CREATE TRIGGER tbiu_sc_fin_cheque_registered
	BEFORE INSERT ON sc_fin_cheque_registered FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_fin_cheque_registered();

